import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaEnvelope, FaLock } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    const res = await loginAdmin(email, password);
    if (res.data.access_token) {
      onLogin(res.data.access_token);
    }
  };

  return (
    <div style={{
      display: "flex",
      height: "100vh",
      fontFamily: "sans-serif"
    }}>

      {/* LEFT SIDE */}
      <div style={{
        flex: 1,
        background: "#F1F5F9",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        padding: "80px"
      }}>
        <h1 style={{
          fontSize: "42px",
          fontWeight: "bold",
          lineHeight: "1.3"
        }}>
          AI-Powered <br />
          <span style={{ color: "#2563EB" }}>Resume Screening</span><br />
          Made Simple
        </h1>

        <p style={{
          marginTop: "20px",
          color: "#64748B",
          fontSize: "16px"
        }}>
          Analyze, rank and hire the best candidates faster using AI.
        </p>

        {/* Optional illustration */}
        <img 
          src="https://cdn-icons-png.flaticon.com/512/3135/3135715.png" 
          alt="AI"
          style={{ width: "300px", marginTop: "40px", opacity: 0.9 }}
        />
      </div>

      {/* RIGHT SIDE */}
      <div style={{
        flex: 1,
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "#FFFFFF"
      }}>

        <div style={{
          width: "380px",
          padding: "40px",
          borderRadius: "16px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.1)"
        }}>

          <h2 style={{
            textAlign: "center",
            marginBottom: "10px",
            fontSize: "26px"
          }}>
            Admin Login
          </h2>

          <p style={{
            textAlign: "center",
            color: "#6B7280",
            marginBottom: "30px"
          }}>
            Welcome back! Please login
          </p>

          <form onSubmit={handleSubmit}>

            {/* EMAIL */}
            <div style={{ marginBottom: "20px", position: "relative" }}>
              <FaEnvelope style={{
                position: "absolute",
                top: "12px",
                left: "12px",
                color: "#9CA3AF"
              }} />

              <input
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{
                  width: "100%",
                  padding: "12px 12px 12px 38px",
                  borderRadius: "10px",
                  border: "1px solid #E5E7EB",
                  outline: "none"
                }}
              />
            </div>

            {/* PASSWORD */}
            <div style={{ marginBottom: "25px", position: "relative" }}>
              <FaLock style={{
                position: "absolute",
                top: "12px",
                left: "12px",
                color: "#9CA3AF"
              }} />

              <input
                type="password"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{
                  width: "100%",
                  padding: "12px 12px 12px 38px",
                  borderRadius: "10px",
                  border: "1px solid #E5E7EB",
                  outline: "none"
                }}
              />
            </div>

            {/* BUTTON */}
            <button style={{
              width: "100%",
              padding: "12px",
              background: "#2563EB",
              color: "white",
              border: "none",
              borderRadius: "10px",
              fontWeight: "bold",
              cursor: "pointer"
            }}>
              Login
            </button>

          </form>

        </div>
      </div>

    </div>
  );
};

export default LoginPage;
